#include<bits/stdc++.h>
#define clr(x) memset(x,0,sizeof(x))
using namespace std;
int n,t,a[1000010],b[1000010],c[1000010],d[1000010],e[1000010];
int main()
{
    scanf("%d",&t);
    while(t--)
    {
        clr(a),clr(b),clr(c),clr(d),clr(e);
        scanf("%d",&n);
        for(int i=1;i<=n;i++)
        {
            scanf("%d",&a[i]);
            b[i]=abs(a[i]-a[1]);
        }
        int ans=abs(a[n]-a[1])+n;
        for(int i=1;i<=n;i++)
        {
            c[i]=abs(a[n]-a[i]);
        }
        d[n]=1e9;
        for(int i=n-1;i>=1;i--)
        {
            if(d[i+1]>c[i])
            {
                d[i]=c[i];
                e[i]=i;
            }
            else
            {
                d[i]=d[i+1];
                e[i]=e[i+1];
            }
        }
        for(int i=2;i<=n-2;i++)
        {
            ans=min({ans,b[i]+c[i+1]+n,b[i]+d[i+1]+n+2});
            if(e[i+1]>i+2)
            {
                ans=min(ans,b[i]+d[i+1]+abs(a[i+1]-a[e[i+1]-1])+n);
            }
        }
        printf("%d\n",ans);
    }
    return 0;
}
